import{_ as e,c as t,o,a1 as l}from"./chunks/framework.DILC4Csi.js";const b=JSON.parse('{"title":"付録 | Clawdbot チュートリアル","description":"Clawdbot の付録章：完全設定リファレンス、Gateway WebSocket API プロトコル、デプロイオプション、開発ガイド。","frontmatter":{"title":"付録 | Clawdbot チュートリアル","sidebarTitle":"設定、デプロイ、開発実践","subtitle":"付録","description":"Clawdbot の付録章：完全設定リファレンス、Gateway WebSocket API プロトコル、デプロイオプション、開発ガイド。","tags":[],"order":340},"headers":[],"relativePath":"ja/moltbot/moltbot/appendix/index.md","filePath":"ja/moltbot/moltbot/appendix/index.md"}'),r={name:"ja/moltbot/moltbot/appendix/index.md"};function i(n,a,s,c,d,h){return o(),t("div",null,[...a[0]||(a[0]=[l('<h1 id="付録" tabindex="-1">付録 <a class="header-anchor" href="#付録" aria-label="Permalink to &quot;付録&quot;">​</a></h1><p>本章では Clawdbot の高度なリファレンスドキュメントと開発リソースを提供します。完全な設定リファレンス、Gateway WebSocket API プロトコル仕様、デプロイオプション、開発ガイドが含まれます。</p><div class="info custom-block"><p class="custom-block-title">対象シナリオ</p><p>本章は Clawdbot の内部メカニズムを深く理解したい、高度な設定を行いたい、デプロイや開発に参加したいユーザーに適しています。初めて使用する場合は、先に<a href="./../../start/getting-started/">クイックスタート</a>章を完了することをお勧めします。</p></div><h2 id="サブページナビゲーション" tabindex="-1">サブページナビゲーション <a class="header-anchor" href="#サブページナビゲーション" aria-label="Permalink to &quot;サブページナビゲーション&quot;">​</a></h2><h3 id="完全設定リファレンス" tabindex="-1"><a href="./config-reference/">完全設定リファレンス</a> <a class="header-anchor" href="#完全設定リファレンス" aria-label="Permalink to &quot;[完全設定リファレンス](./config-reference/)&quot;">​</a></h3><p><strong>詳細設定ファイルリファレンス</strong> - すべての設定項目、デフォルト値、例を網羅。Gateway、Agent、チャンネル、ツールなどのモジュールの完全な設定説明を確認できます。</p><h3 id="gateway-websocket-api-プロトコル" tabindex="-1"><a href="./api-protocol/">Gateway WebSocket API プロトコル</a> <a class="header-anchor" href="#gateway-websocket-api-プロトコル" aria-label="Permalink to &quot;[Gateway WebSocket API プロトコル](./api-protocol/)&quot;">​</a></h3><p><strong>プロトコル仕様ドキュメント</strong> - Gateway WebSocket プロトコルの完全仕様。エンドポイント定義、メッセージ形式、認証方式、イベント購読メカニズムを含みます。カスタムクライアントの作成や Gateway との統合を行う開発者に適しています。</p><h3 id="デプロイオプション" tabindex="-1"><a href="./deployment/">デプロイオプション</a> <a class="header-anchor" href="#デプロイオプション" aria-label="Permalink to &quot;[デプロイオプション](./deployment/)&quot;">​</a></h3><p><strong>デプロイ方法ガイド</strong> - 異なるプラットフォームでのデプロイ方法：ローカルインストール、Docker、VPS、Fly.io、Nix など。さまざまな環境で Clawdbot を実行する方法を学びます。</p><h3 id="開発ガイド" tabindex="-1"><a href="./development/">開発ガイド</a> <a class="header-anchor" href="#開発ガイド" aria-label="Permalink to &quot;[開発ガイド](./development/)&quot;">​</a></h3><p><strong>開発者ドキュメント</strong> - ソースコードからのビルド、プラグイン開発、テスト、貢献のフロー。Clawdbot プロジェクトの開発に参加する方法や、カスタムプラグインを記述する方法を学びます。</p><h2 id="学習パスの推奨" tabindex="-1">学習パスの推奨 <a class="header-anchor" href="#学習パスの推奨" aria-label="Permalink to &quot;学習パスの推奨&quot;">​</a></h2><p>ニーズに合わせて、適切な学習パスを選択してください。</p><h3 id="設定・運用担当者" tabindex="-1">設定・運用担当者 <a class="header-anchor" href="#設定・運用担当者" aria-label="Permalink to &quot;設定・運用担当者&quot;">​</a></h3><ol><li>まず<a href="./config-reference/">完全設定リファレンス</a>を読む - すべての設定可能項目を理解</li><li><a href="./deployment/">デプロイオプション</a>を参照 - 適切なデプロイソリューションを選択</li><li>必要に応じて Gateway WebSocket API ドキュメントを参照して統合</li></ol><h3 id="アプリケーション開発者" tabindex="-1">アプリケーション開発者 <a class="header-anchor" href="#アプリケーション開発者" aria-label="Permalink to &quot;アプリケーション開発者&quot;">​</a></h3><ol><li><a href="./api-protocol/">Gateway WebSocket API プロトコル</a>を読む - プロトコルメカニズムを理解</li><li><a href="./config-reference/">完全設定リファレンス</a>を確認 - 関連機能の設定方法を理解</li><li>プロトコルの例を参照してクライアントを構築</li></ol><h3 id="プラグイン・機能開発者" tabindex="-1">プラグイン・機能開発者 <a class="header-anchor" href="#プラグイン・機能開発者" aria-label="Permalink to &quot;プラグイン・機能開発者&quot;">​</a></h3><ol><li><a href="./development/">開発ガイド</a>を読む - 開発環境とビルドフローを理解</li><li><a href="./api-protocol/">Gateway WebSocket API プロトコル</a>を深く学ぶ - Gateway アーキテクチャを理解</li><li><a href="./config-reference/">完全設定リファレンス</a>を参照 - 設定システムを理解</li></ol><h2 id="前提条件" tabindex="-1">前提条件 <a class="header-anchor" href="#前提条件" aria-label="Permalink to &quot;前提条件&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">前提知識</p><p>本章に深く入る前に、以下を完了することをお勧めします：</p><ul><li>✅ <a href="./../../start/getting-started/">クイックスタート</a>を完了</li><li>✅ 少なくとも1つのチャンネル（<a href="./../../platforms/whatsapp/">WhatsApp</a> や <a href="./../../platforms/telegram/">Telegram</a> など）を設定</li><li>✅ 基本的な AI モデル設定を理解（<a href="./../../advanced/models-auth/">AI モデルと認証</a>参照）</li><li>✅ JSON 設定ファイルと TypeScript の基本知識</li></ul></div><h2 id="次のステップ" tabindex="-1">次のステップ <a class="header-anchor" href="#次のステップ" aria-label="Permalink to &quot;次のステップ&quot;">​</a></h2><p>本章の学習を完了すると、以下が可能になります：</p><ul><li><strong>高度な設定を行う</strong> - <a href="./config-reference/">完全設定リファレンス</a>を参照して Clawdbot をカスタマイズ</li><li><strong>本番環境にデプロイ</strong> - <a href="./deployment/">デプロイオプション</a>に従って適切なデプロイソリューションを選択</li><li><strong>カスタム機能を開発</strong> - <a href="./development/">開発ガイド</a>を参照してプラグインを記述したりコードを貢献したり</li><li><strong>他の機能を深く学ぶ</strong> - <a href="./../../advanced/">高度な機能</a>章を探索。セッション管理、ツールシステムなど</li></ul><div class="tip custom-block"><p class="custom-block-title">ヘルプの探し方</p><p>使用中に問題が発生した場合、<a href="./../../faq/troubleshooting/">トラブルシューティング</a>を参照して一般的な問題の解決策を確認できます。</p></div>',26)])])}const f=e(r,[["render",i]]);export{b as __pageData,f as default};
